import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface GoalData {
  goal: {
    name: string;
    targetAmount: number;
    currentAmount: number;
    percentageCompleted: number;
    projectedCompletionDate: string;
  };
}

export default function Widget() {
  const goalData = response.data as GoalData;
  const { name, targetAmount, currentAmount, percentageCompleted, projectedCompletionDate } = goalData.goal;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: response.meta.primaryColor }}>
              {name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${currentAmount.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of ${targetAmount.toLocaleString()} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: response.meta.primaryColor }}>
                {percentageCompleted}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={percentageCompleted}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#F3F4F6',
                '& .MuiLinearProgress-bar': {
                  bgcolor: response.meta.primaryColor,
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Projected Completion Date
            </Typography>
            <Typography variant="body2" sx={{ color: '#111827', fontWeight: 500 }}>
              {new Date(projectedCompletionDate).toLocaleDateString()}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
